const output = {};

// Helper function to convert value to specified type
const convertType = (value, type) => {
  if (value === undefined || value === null) return value;

  switch(type) {
    case 'number':
      return Number(value);
    case 'boolean':
      if (typeof value === 'boolean') return value;
      if (typeof value === 'string') {
        const lower = value.toLowerCase();
        if (lower === 'true' || lower === '1') return true;
        if (lower === 'false' || lower === '0') return false;
      }
      return Boolean(value);
    case 'string':
      return String(value);
    default:
      return value;
  }
};

for (const item of $input.all()) {
  const key = item.json.key;
  let value = item.json.value;
  const type = item.json.type;

  // Apply type conversion if type is specified
  if (type) {
    value = convertType(value, type);
  }

  // Split by '__' to get path parts
  const parts = key.split('__');

  let current = output;

  for (let i = 0; i < parts.length; i++) {
    const part = parts[i];
    const isLast = i === parts.length - 1;

    // Check if this part is an array index (number)
    const isArrayIndex = /^\d+$/.test(part);

    if (isLast) {
      // Last part - assign the value
      if (isArrayIndex) {
        const idx = parseInt(part);
        current[idx] = value;
      } else {
        current[part] = value;
      }
    } else {
      // Not last part - need to traverse/create structure
      const nextPart = parts[i + 1];
      const nextIsArrayIndex = /^\d+$/.test(nextPart);

      if (isArrayIndex) {
        // Current part is array index
        const idx = parseInt(part);
        if (current[idx] === undefined) {
          // Create array element (object or nested array)
          current[idx] = nextIsArrayIndex ? [] : {};
        }
        current = current[idx];
      } else {
        // Current part is object key
        if (current[part] === undefined) {
          // Create object or array based on next part
          current[part] = nextIsArrayIndex ? [] : {};
        }
        current = current[part];
      }
    }
  }
}

return { json: output };

// Define which fields you need (GraphQL-style)
const required_fields = $('When Executed by Another Workflow').first().json.required_fields || [];
const inputData = $input.first().json;
const output = {};

// If empty array, return everything
if (required_fields.length === 0) {
  return { json: inputData };
}

// Helper function to get nested value
function getNestedValue(obj, path) {
  const parts = path.split('__');
  let current = obj;

  for (const part of parts) {
    if (current === undefined || current === null) return undefined;

    // Check if it's an array index
    if (/^\d+$/.test(part)) {
      current = current[parseInt(part)];
    } else {
      current = current[part];
    }
  }

  return current;
}

// Extract only required fields (flat output - use last key as the output key)
for (const field of required_fields) {
  let value;

  // Check for special fields
  if (field === 'date') {
    value = $now.toFormat('yyyy-MM-dd');
  } else if (field === 'weekday') {
    value = $now.weekdayLong;
  } else {
    value = getNestedValue(inputData, field);
  }

  if (value !== undefined) {
    // Get the last part of the path as the key
    const parts = field.split('__');
    const key = parts[parts.length - 1];
    output[key] = value;
  }
}

return { json: output };
